const stdout = $input.first().json.stdout || '';
const lines = stdout.trim().split('\n').filter(f => f.length > 0);
const MAX_SIZE_BYTES = 100 * 1024 * 1024;
const items = lines.map(line => {
  const spaceIdx = line.indexOf(' ');
  const fileSize = spaceIdx > 0 ? parseInt(line.slice(0, spaceIdx)) : 0;
  const filepath = spaceIdx > 0 ? line.slice(spaceIdx + 1).trim() : line.trim();
  const filename = filepath.split('/').pop();
  const match = filename.match(/^(\d+)[_\-\.]/);
  const leadId = match ? match[1] : 'UNKNOWN';
  const dateMatch = filename.match(/(\d{4}-\d{2}-\d{2})/);
  const fileDate = dateMatch ? dateMatch[1] : new Date().toISOString().slice(0, 10);
  const tooLarge = fileSize > MAX_SIZE_BYTES;
  return { json: { filepath, filename, leadId, fileDate, fileSize, tooLarge } };
}).filter(item => !item.json.tooLarge);
if (items.length === 0) { return [{ json: { _noFiles: true } }]; }
return items;

const filepath = $('Parse Filenames & LEAD_ID').first().json.filepath;
const filename = $('Parse Filenames & LEAD_ID').first().json.filename;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://transcribe:9001/',
    body: JSON.stringify({ filepath: filepath, filename: filename }),
    headers: { 'Content-Type': 'application/json' },
    timeout: 30000
  });
  return [{ json: { ...response, _submitted: true } }];
} catch (e) {
  return [{ json: { _submitted: false, _error: e.message } }];
}

const filename = $('Parse Filenames & LEAD_ID').first().json.filename;
const maxAttempts = 10;
const waitMs = 60000;

for (let i = 0; i < maxAttempts; i++) {
  try {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://transcribe:9001/check',
      body: JSON.stringify({ filename: filename }),
      headers: { 'Content-Type': 'application/json' },
      timeout: 10000
    });
    if (result && result.transcript) {
      return [{ json: { text: result.transcript, attempts: i + 1, filename: filename } }];
    }
    if (i < maxAttempts - 1) { await new Promise(r => setTimeout(r, waitMs)); }
  } catch (e) {
    if (i < maxAttempts - 1) { await new Promise(r => setTimeout(r, waitMs)); }
  }
}
return [{ json: { text: '', _notReady: true, attempts: maxAttempts, filename: filename } }];

const transcript = $input.first().json.text || '';
const leadId = $('Parse Filenames & LEAD_ID').first().json.leadId;
const filename = $('Parse Filenames & LEAD_ID').first().json.filename;
const fileDate = $('Parse Filenames & LEAD_ID').first().json.fileDate;
return [{ json: { transcript: transcript.trim(), leadId, filename, fileDate } }];
